function Toast({ message, visible }: { message: string; visible: boolean }) {
  return (
    <div
      style={{
        position: 'fixed',
        bottom: 28,
        left: '50%',
        transform: `translateX(-50%) translateY(${visible ? '0' : '12px'})`,
        opacity: visible ? 1 : 0,
        transition: 'opacity 0.2s, transform 0.2s',
        pointerEvents: 'none',
        zIndex: 9999,
        background: '#1e2030',
        border: '1px solid rgba(88,101,242,0.5)',
        borderRadius: 8,
        padding: '9px 18px',
        fontFamily: "'JetBrains Mono', monospace",
        fontSize: 12,
        color: '#5865F2',
        whiteSpace: 'nowrap',
        boxShadow: '0 4px 24px rgba(0,0,0,0.5)',
      }}
    >
      ✓ {message}
    </div>
  );
}

function PingDot({ color, size = 8 }: { color: string; size?: number }) {
  return (
    <span
      style={{
        position: 'relative',
        display: 'inline-flex',
        width: size,
        height: size,
        flexShrink: 0,
      }}
    >
      <span
        style={{
          position: 'absolute',
          inset: 0,
          borderRadius: '50%',
          background: color,
          opacity: 0.5,
          animation: 'ping 1.4s cubic-bezier(0,0,0.2,1) infinite',
        }}
      />
      <span
        style={{
          position: 'relative',
          width: size,
          height: size,
          borderRadius: '50%',
          background: color,
        }}
      />
    </span>
  );
}

function useCountUp(target: number, duration = 1500, start = false): number {
  const [val, setVal] = useState(0);
  useEffect(() => {
    if (!start) return;
    let startTime: number | null = null;
    let frameId: number;
    const step = (ts: number) => {
      if (startTime === null) startTime = ts;
      const p = Math.min((ts - startTime) / duration, 1);
      setVal(Math.floor((1 - Math.pow(1 - p, 3)) * target));
      if (p < 1) frameId = requestAnimationFrame(step);
    };
    frameId = requestAnimationFrame(step);
    return () => cancelAnimationFrame(frameId);
  }, [target, duration, start]);
  return val;
}

function StatCard({
  label,
  value,
  suffix,
  delay,
  started,
}: StatItem & { key?: React.Key; delay: number; started: boolean }) {
  const count = useCountUp(value, 1200 + delay * 100, started);
  const isLarge = value >= 10000;
  const [compact, setCompact] = useState(() => {
    try { return localStorage.getItem('stat-compact') === 'true'; } catch { return false; }
  });

  const toggle = () => {
    if (!isLarge) return;
    const next = !compact;
    setCompact(next);
    try { localStorage.setItem('stat-compact', String(next)); } catch {}
  };

  const display = isLarge && compact
    ? `${Math.floor(count / 1000)}K`
    : count.toLocaleString();

  return (
    <div
      className="stat-card"
      style={{
        background: 'var(--surface2)',
        border: '1px solid rgba(88,101,242,0.3)',
        borderRadius: 12,
        textAlign: 'center',
        transition: 'border-color 0.3s',
        cursor: isLarge ? 'pointer' : 'default',
      }}
      onClick={toggle}
      onMouseEnter={(e) => {
        (e.currentTarget as HTMLDivElement).style.borderColor =
          'rgba(88,101,242,0.8)';
      }}
      onMouseLeave={(e) => {
        (e.currentTarget as HTMLDivElement).style.borderColor =
          'rgba(88,101,242,0.3)';
      }}
    >
      <div
        className="stat-value"
        style={{
          fontFamily: "'JetBrains Mono', monospace",
          fontWeight: 700,
          color: '#5865F2',
          letterSpacing: -1,
        }}
      >
        {display}
        {suffix}
      </div>
      <div
        className="stat-label"
        style={{
          fontSize: 12,
          color: 'var(--muted)',
          textTransform: 'uppercase',
          letterSpacing: 1.5,
          marginTop: 4,
        }}
      >
        {label}
      </div>
    </div>
  );
}

function CommandGroup({
  name,
  data,
  isOpen,
  onToggle,
  filtered,
  copiedCmd,
  copyCmd,
}: {
  key?: React.Key;
  name: string;
  data: CommandGroupData;
  isOpen: boolean;
  onToggle: () => void;
  filtered: Cmd[] | undefined;
  copiedCmd: string | null;
  copyCmd: (cmd: Cmd) => void;
}) {
  const contentRef = useRef<HTMLDivElement>(null);
  const [height, setHeight] = useState('0px');
  const cmdsToShow = filtered ?? data.cmds;
  useEffect(() => {
    if (contentRef.current)
      setHeight(isOpen ? `${contentRef.current.scrollHeight}px` : '0px');
  }, [isOpen, cmdsToShow.length]);
  return (
    <div
      style={{
        border: `1px solid ${
          isOpen ? data.color + '55' : 'var(--border)'
        }`,
        borderRadius: 10,
        overflow: 'hidden',
        transition: 'border-color 0.25s',
      }}
    >
      <div
        onClick={onToggle}
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          padding: '14px 18px',
          cursor: 'pointer',
          userSelect: 'none',
          background: isOpen ? `${data.color}18` : 'var(--surface)',
          transition: 'background 0.2s',
        }}
        onMouseEnter={(e) => {
          if (!isOpen)
            (e.currentTarget as HTMLDivElement).style.background =
              'var(--surface2)';
        }}
        onMouseLeave={(e) => {
          if (!isOpen)
            (e.currentTarget as HTMLDivElement).style.background =
              'var(--surface)';
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <span style={{ fontSize: 18 }}>{data.icon}</span>
          <span
            style={{
              fontFamily: "'JetBrains Mono', monospace",
              fontWeight: 600,
              color: 'var(--t)',
              fontSize: 14,
            }}
          >
            {name}
          </span>
          <span
            style={{
              background: `${data.color}33`,
              color: data.color,
              borderRadius: 20,
              padding: '1px 8px',
              fontSize: 11,
              fontFamily: 'monospace',
              fontWeight: 700,
            }}
          >
            {filtered
              ? `${filtered.length}/${data.cmds.length}`
              : data.cmds.length}
          </span>
        </div>
        <span
          style={{
            color: 'var(--muted)',
            fontSize: 12,
            display: 'inline-block',
            transform: isOpen ? 'rotate(90deg)' : 'rotate(0deg)',
            transition: 'transform 0.25s ease',
          }}
        >
          ▶
        </span>
      </div>
      <div
        style={{
          maxHeight: height,
          overflow: 'hidden',
          transition: 'max-height 0.35s cubic-bezier(0.4,0,0.2,1)',
        }}
      >
        <div ref={contentRef} style={{ padding: '4px 0 8px' }}>
          {cmdsToShow.map((cmd, i) => {
            const cmdText = cmd.args
              ? `#$${cmd.name} ${cmd.args}`
              : `#$${cmd.name}`;
            const isCopied = copiedCmd === cmdText;
            return (
              <div
                key={i}
                onClick={() => copyCmd(cmd)}
                style={{
                  display: 'flex',
                  alignItems: 'flex-start',
                  gap: 12,
                  padding: '8px 18px',
                  borderBottom:
                    i < cmdsToShow.length - 1
                      ? '1px solid var(--border)'
                      : 'none',
                  cursor: 'pointer',
                  transition: 'background 0.15s',
                  background: isCopied ? `${data.color}18` : 'transparent',
                }}
                onMouseEnter={(e) => {
                  if (!isCopied)
                    (e.currentTarget as HTMLDivElement).style.background =
                      'var(--surface2)';
                }}
                onMouseLeave={(e) => {
                  if (!isCopied)
                    (e.currentTarget as HTMLDivElement).style.background =
                      'transparent';
                }}
              >
                <div style={{ minWidth: 210 }}>
                  <span
                    style={{
                      fontFamily: "'JetBrains Mono', monospace",
                      fontSize: 12,
                      color: data.color,
                      fontWeight: 700,
                    }}
                  >
                    #${cmd.name}
                  </span>
                  {cmd.args && (
                    <span
                      style={{
                        fontFamily: "'JetBrains Mono', monospace",
                        fontSize: 11,
                        color: 'var(--muted)',
                      }}
                    >
                      {' '}
                      {cmd.args}
                    </span>
                  )}
                </div>
                <div
                  style={{
                    fontSize: 12,
                    color: 'var(--muted)',
                    lineHeight: 1.6,
                    flex: 1,
                  }}
                >
                  {cmd.desc}
                </div>
                <span
                  style={{
                    fontSize: 10,
                    fontFamily: 'monospace',
                    fontWeight: 700,
                    color: PERM_COLORS[cmd.perm],
                    background: `${PERM_COLORS[cmd.perm]}18`,
                    border: `1px solid ${PERM_COLORS[cmd.perm]}44`,
                    borderRadius: 4,
                    padding: '1px 6px',
                    flexShrink: 0,
                    alignSelf: 'center',
                    whiteSpace: 'nowrap',
                  }}
                >
                  {cmd.perm}
                </span>
                <div
                  style={{
                    fontSize: 10,
                    fontFamily: 'monospace',
                    color: isCopied ? data.color : 'var(--faint)',
                    marginLeft: 8,
                    flexShrink: 0,
                    alignSelf: 'center',
                    transition: 'color 0.2s',
                  }}
                >
                  {isCopied ? '✓ copied' : 'click to copy'}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

